import { action } from "./_generated/server";
import { v } from "convex/values";

// Example images (base64) from training dataset
const EXAMPLES = [
  {
    // clean example 1 - score 90
    image: "",
    result: { score: 90, category: "bersih", recommendation: "Jalan dalam kondisi bersih. Pertahankan dengan perawatan rutin." }
  },

  {
    // clean example 2 - score 85
    image: "",
    result: { score: 85, category: "bersih", recommendation: "Trotoar bersih dan tertata dengan baik." }
  },

  {
    // dirty example 3 - score 20
    image: "",
    result: { score: 20, category: "kotor", recommendation: "Banyak sampah terlihat. Segera kirim tim pembersih." }
  },

  {
    // dirty example 4 - score 15
    image: "",
    result: { score: 15, category: "kotor", recommendation: "Kondisi kritis. Lingkungan sangat kotor dengan banyak sampah." }
  },

  {
    // clean example 5 - score 80
    image: "",
    result: { score: 80, category: "bersih", recommendation: "Jalan bersih dengan trotoar yang tertata rapih." }
  },

  {
    // sedang example 6 - score 55
    image: "",
    result: { score: 55, category: "sedang", recommendation: "Kondisi sedang, ada sampah ringan yang perlu dibersihkan." }
  },

  {
    // sedang example 7 - score 60
    image: "",
    result: { score: 60, category: "sedang", recommendation: "Trotoar perlu sedikit perbaikan dan pembersihan." }
  },
];



export const analyzeImage = action({
  args: {
    imageBase64: v.string(),
    mimeType: v.string(),
  },
  handler: async (_ctx, args) => {
    const apiKey = process.env.MISTRAL_API_KEY;
    
    if (!apiKey) {
      throw new Error("MISTRAL_API_KEY not set in Convex Dashboard");
    }

    const instructionText = `Anda adalah ahli kebersihan lingkungan Indonesia.

Berdasarkan 7 contoh gambar sebelumnya (3 bersih, 2 kotor, 2 sedang), analisis gambar baru ini untuk menilai tingkat KEBERSIHAN JALAN/LINGKUNGAN.

FOKUS ANALISA (hanya ini yang dinilai):
- Sampah yang terlihat di jalan, trotoar, atau area outdoor
- Kondisi infrastruktur jalan: lubang, kerusakan, retakan
- Vegetasi yang tidak terawat
- Genangan air/kotoran
- Polusi visual

ABAIKAN jika gambar:
- Hanya menampilkan orang tanpa jalan
- Interior ruangan
- Kendaraan tanpa jalan
- Makanan/minuman dalam ruangan

PENTING: Selalu berikan score 0-100 meskipun gambarnya tidak jelas lingkungan atau bukan.

Jawab dalam bahasa Indonesia dengan format JSON:
{"score": 0-100, "category": "bersih/sedang/kotor", "recommendation": "...", "isEnvironment": true/false, "reason": "penjelasan singkat"}

Panduan score:
- Score 70-100: Bersih - tidak ada sampah terlihat
- Score 40-69: Sedang - ada sedikit sampah
- Score 0-39: Kotor - banyak sampah`;

    // Build messages with examples (few-shot learning)
    const messages = [
      // Example 1 - Clean
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar jalan ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[0].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[0].result) }]
      },
      // Example 2 - Clean
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[1].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[1].result) }]
      },
      // Example 3 - Dirty
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar jalan ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[2].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[2].result) }]
      },
      // Example 4 - Dirty
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[3].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[3].result) }]
      },
      // Example 5 - Clean (score 80)
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar jalan ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[4].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[4].result) }]
      },
      // Example 6 - Clean (score 75)
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[5].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[5].result) }]
      },
      // Example 7 - Sedang (score 60)
      {
        role: "user",
        content: [
          { type: "text", text: "Analisis gambar ini." },
          { type: "image_url", image_url: { url: `data:image/jpeg;base64,${EXAMPLES[6].image}` } }
        ]
      },
      {
        role: "assistant",
        content: [{ type: "text", text: JSON.stringify(EXAMPLES[6].result) }]
      },
      // Final question with new image
      {
        role: "user",
        content: [
          { type: "text", text: instructionText },
          { type: "image_url", image_url: { url: `data:${args.mimeType};base64,${args.imageBase64}` } }
        ]
      }
    ];

    const response = await fetch(
      "https://api.mistral.ai/v1/chat/completions",
      {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: "pixtral-12b-2409",
          response_format: { type: "json_object" },
          messages: messages
        }),
      }
    );

    if (!response.ok) {
      const errText = await response.text();
      console.error("Mistral Error:", errText);
      
      if (response.status === 429 || errText.includes("quota") || errText.includes("Rate limit")) {
        console.log("Menggunakan Fallback karena API Quota Habis...");
        const score = Math.floor(Math.random() * 60) + 20;
        const category = score >= 70 ? "sedang" : score >= 40 ? "sedang" : "kotor";
        const recommendations: Record<string, string> = {
          bersih: "Jalan dalam kondisi baik. Pertahankan dengan perawatan rutin.",
          sedang: "Ada beberapa sampah. Segera bersihkan untuk mencegah penumpukan.",
          kotor: "Kondisi kritis! Segala bentuk tim pembersih diperlukan segera ke lokasi."
        };
        return {
          score,
          category,
          recommendation: `${recommendations[category]} (Hasil simulasi karena API error)`
        };
      }

      throw new Error(`Mistral API Error (${response.status}): ${errText}`);
    }

    const data = await response.json();
    const resultText = data.choices[0]?.message?.content;
    
    if (!resultText) {
      throw new Error("Invalid response from Mistral");
    }

    try {
      const parsed = JSON.parse(resultText.trim());
      
      // Handle recommendation - bisa object atau string
      let recText = parsed.recommendation;
      if (typeof recText === 'object' && recText !== null) {
        recText = Object.entries(recText)
          .map(([key, value]) => `• ${key.replace(/_/g, ' ')}: ${value}`)
          .join('\n');
      }
      
      if (!recText) {
        recText = "Kondisi jalan perlu diperbaiki. Lakukan pembersihan dan perawatan rutin.";
      }
      
      return {
        score: parsed.score ?? 0,
        category: parsed.category ?? "sedang",
        recommendation: recText,
        isEnvironment: parsed.isEnvironment ?? true,
        reason: parsed.reason ?? "Gambar dianalisis sebagai lingkungan jalan",
      };
    } catch (e) {
      console.error("Failed to parse Mistral JSON:", e, "Raw:", resultText);
      throw new Error("Failed to parse output as JSON: " + resultText);
    }
  },
});